#include<bits/stdc++.h>

using namespace std;

int n;
class tong {
public:
		string name;
		int c;
		int m;
		int e;
		int z;


};
class tongs {
public:
		tong a[100001];

		void in(string name1, int c1, int m1, int e1, int i) {
			a[i].name = name1;
			a[i].c = c1;
			a[i].m = m1;
			a[i].e = e1;
			a[i].z = c1 + m1 + e1;
		}
		void bi() {
			for (int i = 0; i < n; i++) {
				for (int j = i+1; j < n; j++) {
					if (abs(a[i].c - a[j].c) <= 5 && abs(a[i].m - a[j].m) <= 5 && abs(a[i].e - a[j].e) <= 5 && abs(a[i].z - a[j].z) <= 10) {

							cout << a[i].name << " " << a[j].name << endl;

					}
				}
			}

		}
};
tongs a;

int main () {
	cin >> n;
	for (int i = 0; i < n; i++) {
		string name1;
		int c1, m1, e1;
		cin >> name1 >> c1 >> m1 >> e1;
		a.in(name1, c1, m1, e1, i);
	}
	a.bi();

	return 0;
}
